 1	import type { FC } from 'react';
 2	
 3	import { ExpandableRowContent, Td, Tr } from '@patternfly/react-table';
 4	
 5	import type { RowProps } from './types';
 6	
 7	export const withTr = <T,>(
 8	  Component: FC<RowProps<T>>,
 9	  ExpandedComponent?: FC<RowProps<T>>,
10	): FC<RowProps<T>> => {
11	  const Enhanced = (props: RowProps<T>) => {
12	    const { isExpanded, length } = props;
13	
14	    if (ExpandedComponent) {
15	      return (
16	        <>
17	          <Tr>
18	            <Component {...props} />
19	          </Tr>
20	          <Tr isExpanded={isExpanded}>
21	            <Td />
22	            <Td noPadding colSpan={length}>
23	              {isExpanded && (
24	                <ExpandableRowContent>
25	                  <ExpandedComponent {...props} />
26	                </ExpandableRowContent>
27	              )}
28	            </Td>
29	          </Tr>
30	        </>
31	      );
32	    }
33	
34	    return (
35	      <Tr>
36	        <Component {...props} />
37	      </Tr>
38	    );
39	  };
40	
41	  return Enhanced;
42	};

